#!/bin/zsh
# test.sh — Build and run tests across the codebase

cd "$(dirname "$0")" || exit 1

copilot -p "You are a senior test engineer. Look at the codebase, detect the language and test framework in use (or choose the standard one for the language), and write thorough tests for every module that has real implementation — skip stubs and empty files. Reference ENGINEERING_STANDARDS.md (if it exists) — tests should follow the same conventions as production code. For each module, test the happy path, edge cases, and error handling. If a test directory doesn't exist, create one. If tests already exist, review them for coverage gaps and add what's missing. Then run the full test suite. If a test fails, determine the root cause. Use PLAN.md (module contracts and expected behavior) and BACKLOG.md (story requirements) as the source of truth — not the current code. If the test correctly reflects the spec'd behavior but the code is wrong, leave the test as-is and report the failure. If the test doesn't match the spec'd behavior, fix the test. Never modify production code. Keep tests focused, fast, and independent — no shared mutable state between tests. Mock external I/O (subprocess calls, disk reads, network) so tests are deterministic. Git commit your changes and push to the remote when done." --yolo
